-- Seed: 81 cursos "Aplicados a Data Centers" — todos em_breve + pago.
-- Idempotente: só insere o curso se ainda não existir outro com o mesmo nome.
-- status='em_breve'  -> selo "Em Breve" + botão "Tenho interesse"
-- acesso='pago'      -> marcado como Curso Pago (preço definido depois no painel de venda)
-- a_venda=false, preco=NULL -> em breve o preço não aparece no card.
-- image aponta para public/images/courses/<arquivo>.png (arquivos versionados no repo).

INSERT INTO cursos (nome, image, descricao_curta, descricao, categoria, nivel, status, acesso, visivel, a_venda)
SELECT v.nome, v.image, v.descricao_curta, v.descricao, v.categoria, v.nivel,
       'em_breve', 'pago', true, false
FROM (VALUES
 ('Agentes Limpos Aplicados a Data Centers','images/courses/Agentes Limpos Aplicados a Data Centers.png','Supressão de incêndio por agentes limpos (FM-200, Novec, inergen) em salas críticas.','Fundamentos, operação e manutenção de sistemas de supressão por agentes limpos usados para proteger salas de TI sem danificar equipamentos. Aborda cilindros, acionamento, concentração de projeto e testes periódicos.','Combate a Incêndio','intermediario'),
 ('Air Handling Unit (AHU) Aplicada a Data Centers','images/courses/Air Handling Unit (AHU) Aplicada a Data Centers.png','Operação e manutenção de unidades de tratamento de ar (AHU) em ambientes de missão crítica.','Princípios de funcionamento, componentes e rotinas de O&M de AHUs aplicadas ao condicionamento de salas de dados. Inclui controle de vazão, filtragem, serpentinas e integração com o sistema de refrigeração.','Mecânica e Climatização','intermediario'),
